#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N,K,L; scanf("%lld %lld %lld", &N, &K, &L);
        long long overlap = (K + L > N) ? (K + L - N) : 0;
        long long a = K - overlap; // pure sources
        long long b = L - overlap; // pure sinks
        long long m = N - K - L + overlap; // middle vertices
        __int128 ans = 0;
        ans += ( (__int128)a * m );
        ans += ( (__int128)a * b );
        ans += ( (__int128)m * b );
        ans += ( (__int128)m * (m - 1) / 2 );
        long long out = (long long)ans; // fits in 64‑bit for given limits
        printf("%lld\n", out);
    }
    return 0;
}

