import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for(int t=0; t<T; t++){
            StringTokenizer st = new StringTokenizer(br.readLine());
            long N = Long.parseLong(st.nextToken());
            long K = Long.parseLong(st.nextToken());
            long L = Long.parseLong(st.nextToken());
            long overlap = (K + L > N) ? (K + L - N) : 0L;
            long a = K - overlap; // pure sources
            long b = L - overlap; // pure sinks
            long m = N - K - L + overlap; // middle vertices
            // use BigInteger to avoid overflow, but long is enough for limits
            java.math.BigInteger ans = java.math.BigInteger.valueOf(a).multiply(java.math.BigInteger.valueOf(m))
                .add(java.math.BigInteger.valueOf(a).multiply(java.math.BigInteger.valueOf(b)))
                .add(java.math.BigInteger.valueOf(m).multiply(java.math.BigInteger.valueOf(b)))
                .add(java.math.BigInteger.valueOf(m).multiply(java.math.BigInteger.valueOf(m-1)).divide(java.math.BigInteger.valueOf(2)));
            sb.append(ans.toString()).append('\n');
        }
        System.out.print(sb.toString());
    }
}

